parameters.jsCode:
const body = $input.first().json.body || $input.first().json;

const lead = {
  full_name: body.full_name || body.name || 'Unknown',
  email: body.email || null,
  phone: body.phone || body.mobile,
  whatsapp_number: body.whatsapp || body.phone,
  source: body.source || 'n8n_webhook',
  status: 'new',
  score: 0,
  budget_min: body.budget_min || null,
  budget_max: body.budget_max || null,
  preferred_property_type: body.property_type || null,
  preferred_locations: body.locations || [],
  city: body.city || 'Chennai',
  state: body.state || 'Tamil Nadu',
  metadata: { raw_payload: body, received_at: new Date().toISOString() }
};

if (!lead.phone) {
  throw new Error('phone is required');
}

return [{ json: lead }];

